resource.manifest:
apiVersion: migrations.opensearch.org/v1alpha1
kind: SnapshotMigration
metadata:
  name: "{{inputs.parameters.resourceName}}"
  labels:
    workflows.argoproj.io/workflow: "{{workflow.name}}"
    workflows.argoproj.io/run-uid: "{{workflow.uid}}"
    migrations.opensearch.org/source: "{{=fromJSON(inputs.parameters.snapshotMigrationConfig)['sourceLabel']}}"
    migrations.opensearch.org/target: "{{=sprig.dig('targetConfig', 'label', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
    migrations.opensearch.org/snapshot: "{{=sprig.dig('snapshotConfig', 'label', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
    migrations.opensearch.org/from-snapshot-migration: "{{=fromJSON(inputs.parameters.snapshotMigrationConfig)['migrationLabel']}}"
spec:
  migrationLabel: "{{=fromJSON(inputs.parameters.snapshotMigrationConfig)['migrationLabel']}}"
  sourceVersion: "{{=fromJSON(inputs.parameters.snapshotMigrationConfig)['sourceVersion']}}"
  sourceLabel: "{{=fromJSON(inputs.parameters.snapshotMigrationConfig)['sourceLabel']}}"
  targetLabel: "{{=sprig.dig('targetConfig', 'label', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  snapshotLabel: "{{=sprig.dig('snapshotConfig', 'label', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationJvmArgs: "{{=sprig.dig('metadataMigrationConfig', 'jvmArgs', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationLoggingConfigurationOverrideConfigMap: "{{=sprig.dig('metadataMigrationConfig', 'loggingConfigurationOverrideConfigMap', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationComponentTemplateAllowlist: {{=sprig.dig('metadataMigrationConfig', 'componentTemplateAllowlist', [], fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  metadataMigrationIndexAllowlist: {{=sprig.dig('metadataMigrationConfig', 'indexAllowlist', [], fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  metadataMigrationIndexTemplateAllowlist: {{=sprig.dig('metadataMigrationConfig', 'indexTemplateAllowlist', [], fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  metadataMigrationAllowLooseVersionMatching: {{=sprig.dig('metadataMigrationConfig', 'allowLooseVersionMatching', true, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  metadataMigrationClusterAwarenessAttributes: {{=sprig.dig('metadataMigrationConfig', 'clusterAwarenessAttributes', 1, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  metadataMigrationEnableSourcelessMigrations: {{=sprig.dig('metadataMigrationConfig', 'enableSourcelessMigrations', false, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  metadataMigrationUseRecoverySource: {{=sprig.dig('metadataMigrationConfig', 'useRecoverySource', false, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  metadataMigrationMultiTypeBehavior: "{{=sprig.dig('metadataMigrationConfig', 'multiTypeBehavior', 'NONE', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationOtelCollectorEndpoint: "{{=sprig.dig('metadataMigrationConfig', 'otelCollectorEndpoint', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationOutput: "{{=sprig.dig('metadataMigrationConfig', 'output', 'HUMAN_READABLE', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationTransformerConfigBase64: "{{=sprig.dig('metadataMigrationConfig', 'transformerConfigBase64', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationTransformerConfig: {{=toJSON(sprig.dig('metadataMigrationConfig', 'transformerConfig', '', fromJSON(inputs.parameters.snapshotMigrationConfig)))}}
  metadataMigrationTransformerConfigFile: "{{=sprig.dig('metadataMigrationConfig', 'transformerConfigFile', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationTransformsImage: {{=toJSON(sprig.dig('metadataMigrationConfig', 'transformsImage', '', fromJSON(inputs.parameters.snapshotMigrationConfig)))}}
  metadataMigrationTransformsImagePullPolicy: "{{=sprig.dig('metadataMigrationConfig', 'transformsImagePullPolicy', 'IfNotPresent', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  metadataMigrationTransformsConfigMap: {{=toJSON(sprig.dig('metadataMigrationConfig', 'transformsConfigMap', '', fromJSON(inputs.parameters.snapshotMigrationConfig)))}}
  documentBackfillPodReplicas: {{=sprig.dig('documentBackfillConfig', 'podReplicas', 1, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillJvmArgs: "{{=sprig.dig('documentBackfillConfig', 'jvmArgs', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillLoggingConfigurationOverrideConfigMap: "{{=sprig.dig('documentBackfillConfig', 'loggingConfigurationOverrideConfigMap', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillUseTargetClusterForWorkCoordination: {{=sprig.dig('documentBackfillConfig', 'useTargetClusterForWorkCoordination', false, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillResources: {{=sprig.dig('documentBackfillConfig', 'resources', sprig.dict(), fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillIndexAllowlist: {{=sprig.dig('documentBackfillConfig', 'indexAllowlist', [], fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillAllowLooseVersionMatching: {{=sprig.dig('documentBackfillConfig', 'allowLooseVersionMatching', true, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillEnableSourcelessMigrations: {{=sprig.dig('documentBackfillConfig', 'enableSourcelessMigrations', false, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillUseRecoverySource: {{=sprig.dig('documentBackfillConfig', 'useRecoverySource', false, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillDocTransformerConfigBase64: "{{=sprig.dig('documentBackfillConfig', 'docTransformerConfigBase64', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillDocTransformerConfig: {{=toJSON(sprig.dig('documentBackfillConfig', 'docTransformerConfig', '', fromJSON(inputs.parameters.snapshotMigrationConfig)))}}
  documentBackfillDocTransformerConfigFile: "{{=sprig.dig('documentBackfillConfig', 'docTransformerConfigFile', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillTransformsImage: {{=toJSON(sprig.dig('documentBackfillConfig', 'transformsImage', '', fromJSON(inputs.parameters.snapshotMigrationConfig)))}}
  documentBackfillTransformsImagePullPolicy: "{{=sprig.dig('documentBackfillConfig', 'transformsImagePullPolicy', 'IfNotPresent', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillTransformsConfigMap: {{=toJSON(sprig.dig('documentBackfillConfig', 'transformsConfigMap', '', fromJSON(inputs.parameters.snapshotMigrationConfig)))}}
  documentBackfillDocumentsPerBulkRequest: {{=sprig.dig('documentBackfillConfig', 'documentsPerBulkRequest', 2147483647, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillDocumentsSizePerBulkRequest: {{=sprig.dig('documentBackfillConfig', 'documentsSizePerBulkRequest', 10485760, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillInitialLeaseDuration: "{{=sprig.dig('documentBackfillConfig', 'initialLeaseDuration', 'PT1H', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillMaxConnections: {{=sprig.dig('documentBackfillConfig', 'maxConnections', 10, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillMaxShardSizeBytes: {{=sprig.dig('documentBackfillConfig', 'maxShardSizeBytes', 85899345920, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillOtelCollectorEndpoint: "{{=sprig.dig('documentBackfillConfig', 'otelCollectorEndpoint', '', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillServerGeneratedIds: "{{=sprig.dig('documentBackfillConfig', 'serverGeneratedIds', 'AUTO', fromJSON(inputs.parameters.snapshotMigrationConfig))}}"
  documentBackfillAllowedDocExceptionTypes: {{=sprig.dig('documentBackfillConfig', 'allowedDocExceptionTypes', [], fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillCoordinatorRetryMaxRetries: {{=sprig.dig('documentBackfillConfig', 'coordinatorRetryMaxRetries', 7, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillCoordinatorRetryInitialDelayMs: {{=sprig.dig('documentBackfillConfig', 'coordinatorRetryInitialDelayMs', 1000, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
  documentBackfillCoordinatorRetryMaxDelayMs: {{=sprig.dig('documentBackfillConfig', 'coordinatorRetryMaxDelayMs', 64000, fromJSON(inputs.parameters.snapshotMigrationConfig))}}
